import rmf_adapter
from rmf_adapter import Adapter

def setup_adapter(node_name='my_fleet_adapter', config_yaml='./config.yaml'):
    adapter = Adapter.make(node_name)
    fleet = adapter.add_fleet('my_amr_fleet',
                              traits={'profile': 'differential', 'radius': 0.4})
    # Robot loop: report state, accept tasks
    @fleet.on_robot_added
    def on_added(robot):
        robot.update_position('lobby_node', heading=0.0)
    return adapter

if __name__ == '__main__':
    a = setup_adapter()
    a.start()
    import rclpy; rclpy.spin(a.node)
